INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-lakefusion', 'lakefusion', 'www.lakefusion.ai', 'https://www.lakefusion.ai', 'LakeFusion', 'Databricks-native master data management for golden records.', 'The interesting move is refusing to be another MDM system outside the warehouse. LakeFusion installs through AWS or Azure Marketplace, runs inside Databricks, and uses LLM plus vector matching to create governed golden records under Unity Catalog. Unlike legacy match-rule projects, the bet is zero data egress, real-time sync back to source systems, and weeks-to-value. The risk is Databricks-native being a moat only if buyers already live there.', 4, '$7.5M Seed for Databricks MDM', 'SaaS', 'Seed', '$7.5M', NULL, NULL, NULL, 'US', 'data management,databricks,mdm,ai', 'Silverton Partners', '{"linkedin": "https://www.linkedin.com/company/lakefusion-ai/"}', 1, 'lakefusion.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-linear', 'linear', 'linear.app', 'https://linear.app', 'Linear', 'Issue tracking built for modern software teams.', 'Someone finally rebuilt project management for teams that live on the keyboard. Keyboard shortcuts, a stripped-back issue flow, and an interface that stays out of the way make it feel closer to an editor than Jira. In a market full of feature-bloated software, Linear chose speed and restraint. That trade only works if you are willing to say no more often than your competitors.', 5, 'Defined a new standard for dev tools', 'DevTools', 'Series C', '$82M', 2019, '50-100', 'San Francisco', 'US', 'project management,issue tracking,developer tools,productivity', 'Sequoia Capital, 01 Advisors, SV Angel', '{"github": "https://github.com/linear", "twitter": "https://x.com/linear", "linkedin": "https://linkedin.com/company/linear"}', 1, 'linear.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excl