INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-liquid-instruments', 'liquid-instruments', 'www.liquidinstruments.com', 'https://www.liquidinstruments.com', 'Liquid Instruments', 'Software-defined test instruments for engineering labs.', 'This is what test equipment looks like when software wins over the bench rack. Liquid Instruments turns Moku hardware into 15+ instruments, switches setups in seconds, and lets teams build custom measurement systems with FPGA-backed processing. Unlike another oscilloscope vendor, it treats instrumentation as a reconfigurable platform. The question is whether AI customization becomes a workflow, not just a lab upgrade.', 5, '15+ instruments in one Moku', 'Other', 'Series C', '$50M', NULL, NULL, NULL, 'US', 'test equipment,instrumentation,fpga,engineering tools', 'Keysight Technologies', NULL, 1, 'liquid-instruments.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excl