INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-resend', 'resend', 'resend.com', 'https://resend.com', 'Resend', 'Email API for developers. Beautiful, simple, reliable.', 'Transactional email used to feel like plumbing you tolerated, not a product you enjoyed. Resend changed that with a cleaner API surface and React Email as a companion project. That pairing reveals the bet: email delivery and email design should live in the same developer workflow. It feels closer to Stripe-grade DX than legacy SMTP tooling.', 4, 'DX that makes you jealous', 'DevTools', 'Seed', '$3M', 2022, '10-30', 'San Francisco', 'US', 'email,api,developer tools,transactional email', 'Y Combinator, SV Angel, Dylan Field', '{"github": "https://github.com/resend", "twitter": "https://x.com/resabordar", "linkedin": "https://linkedin.com/company/resend"}', 1, 'resend.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot