INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-shapes', 'shapes', 'talk.shapes.inc', 'https://talk.shapes.inc', 'Shapes', 'Social AI chat app where people and bots share group conversations.', 'Most AI companion apps trap users in one-on-one confession booths; this points the format back toward messy group chat. The public surface shows 300+ models, message counts like 86.8K on individual characters, and mobile app links instead of a blank waitlist. That choice makes AI feel closer to Discord roleplay than a therapist clone. The hard part is moderation: social AI gets more interesting exactly where it gets harder to keep safe.', 4, 'AI companions in group chat', 'AI / ML', 'Seed', '$8M', 2023, '10-30', 'San Francisco', 'US', 'social ai,chat,consumer,ai companions', 'Lightspeed Venture Partners, Betaworks, Hartbeat Ventures, The Games Fund', NULL, 1, 'shapes.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-supabase', 'supabase', 'supabase.com', 'https://supabase.com', 'Supabase', 'The open source Firebase alternative.', 'The clever part is not calling itself an open-source Firebase alternative. The clever part is turning Postgres into the center of an entire developer stack: auth, storage, realtime, and edge functions. Where most backend platforms hide the database behind abstractions, Supabase leans into it. That makes the product more opinionated and easier to reason about than a generic backend cloud.', 4, 'Postgres as a platform', 'DevTools', 'Series B', '$80M', 2020, '100-200', 'Singapore', 'Global / Remote', 'database,open source,backend,postgres,firebase alternative', 'Felicis Ventures, Coatue Management, Y Combinator', '{"github": "https://github.com/supabase", "twitter": "https://x.com/supabase", "linkedin": "https://linkedin.com/company/supabase"}', 0, 'supabase.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-synera', 'synera', 'www.synera.io', 'https://www.synera.io', 'Synera', 'Agent platform for engineering workflows across CAD, FEA, costing, and reporting tools.', 'The interesting bet is that engineers do not need another copilot; they need a workbench where agents can operate CAD, FEA, cost, and reporting tools. Synera connects 80+ hardware-engineering systems with a node-based editor, 3D viewer, custom nodes, Python scripts, and token licensing. Unlike generic AI-for-manufacturing pitches, this starts from the messy CAx toolchain. The risk is that enterprise deployment turns the agents into services work.', 5, 'Agents across 80+ engineering tools', 'SaaS', 'Series B', '$40M', NULL, NULL, NULL, 'Europe', 'engineering,ai agents,cad,industrial software', 'Revaia', NULL, 1, 'synera.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = excluded.screenshot_status, workflow_status = excluded.workflow_status, codex_stage = excluded.codex_stage, first_seen_at = COALESCE(startups.first_seen_at, excluded.first_seen_at), published_at = COALESCE(startups.published_at, excluded.published_at), created_at = COALESCE(startups.created_at, datetime('now')), updated_at = COALESCE(startups.updated_at, datetime('now'));
INSERT INTO startups (id, slug, domain, canonical_url, product_name, summary, editor_note, editor_rating, why_featured, product_type, funding_stage, funding_display, founded_year, team_size, hq_location, region, tags, investors, links_json, is_featured, screenshot_r2_key, screenshot_status, workflow_status, codex_stage, first_seen_at, published_at) VALUES ('startup-val-town', 'val-town', 'val.town', 'https://val.town', 'Val Town', 'Social website and API for writing and running code.', 'Putting running code inside a social feed sounds gimmicky until you try it. Every val is a URL, every function is deployable, and the product turns tiny scripts into shareable building blocks. That is a real bet against repo-first developer tooling. It feels closer to what Gists wanted to be than another serverless dashboard.', 4, 'Code as social media', 'DevTools', 'Seed', '$5.5M', 2022, '5-10', 'Brooklyn', 'US', 'social coding,serverless,developer tools,code sharing', 'Sequoia Capital Scout, Craft Ventures, Tom Preston-Werner', '{"github": "https://github.com/val-town", "twitter": "https://x.com/valabordar", "linkedin": "https://linkedin.com/company/val-town"}', 0, 'val-town.webp', 'ready', 'published', 'manual', datetime('now'), datetime('now')) ON CONFLICT(slug) DO UPDATE SET id = excluded.id, domain = excluded.domain, canonical_url = excluded.canonical_url, product_name = excluded.product_name, summary = excluded.summary, editor_note = excluded.editor_note, editor_rating = excluded.editor_rating, why_featured = excluded.why_featured, product_type = excluded.product_type, funding_stage = excluded.funding_stage, funding_display = excluded.funding_display, founded_year = excluded.founded_year, team_size = excluded.team_size, hq_location = excluded.hq_location, region = excluded.region, tags = excluded.tags, investors = excluded.investors, links_json = excluded.links_json, is_featured = excluded.is_featured, screenshot_r2_key = excluded.screenshot_r2_key, screenshot_status = exclude